import jwt
from datetime import datetime, timedelta

SECRET_KEY = 'your_secret_key'
ALGORITHM = 'HS256'  # Hash-based Signature Algorithm (HMAC)
ACCESS_TOKEN_EXPIRE_MINUTES = 30  # Expire time for the token in minutes

def create_access_token(user_id: str, user_role: str):
    data = {
        'sub': user_id,  # subject - who this token is about (user id)
        'role': user_role,
        'exp': datetime.utcnow() + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES),  # expiration time
    }
    return jwt.encode(data, SECRET_KEY, algorithm=ALGORITHM)